1. First, you need to install Discord.js v14 by running the following command in your terminal:
```
npm install discord.js@14
```
2. Create a new file for your bot, for example `bot.js`, and add the following code:
```javascript
const { Client, Intents } = require('discord.js');
const { token } = require('./config.json');

const client = new Client({ intents: [Intents.FLAGS.Guilds, Intents.FLAGS.GuildMembers] });

client.once('ready', () => {
  console.log('Ready!');
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  const { commandName } = interaction;

  if (commandName === 'ban') {
    const user = interaction.options.getUser('user');
    const reason = interaction.options.getString('reason') || 'No reason provided';

    if (!interaction.member.permissions.has('BAN_MEMBERS')) {
      return interaction.reply({ content: 'You do not have permission to ban members.', ephemeral: true });
    }

    if (!user) {
      return interaction.reply({ content: 'You must mention a user to ban.', ephemeral: true });
    }

    try {
      await interaction.guild.members.ban(user, { reason });
      interaction.reply({ content: `Banned ${user.username}#${user.discriminator}`, ephemeral: true });
    } catch (error) {
      console.error(error);
      interaction.reply({ content: 'There was an error trying to ban that user.', ephemeral: true });
    }
  }
});

client.login(token);
```
3. Create a `config.json` file in the same directory as your `bot.js` file and add the following code:
```json
{
  "token": "your-bot-token-here"
}
```
Replace `your-bot-token-here` with your actual bot token.

4. In your terminal, run the following command to start your bot:
```
node bot.js
```
5. To create the `ban` command, go to the Discord Developer Portal, select your application, and go to the "Slash Commands" tab. Click on "New Command" and add the following code:
```json
{
  "name": "ban",
  "description": "Ban a user from the server",
  "options": [
    {
      "type": 6,
      "name": "user",
      "description": "The user to ban",
      "required": true
    },
    {
      "type": 3,
      "name": "reason",
      "description": "The reason for the ban"
    }
  ]
}
```
6. Save the command and invite your bot to your server.
7. Your bot should now be able to ban users using the `/ban` command.

